SELECT id, name, parent_id, is_dir, size, create_time FROM file_node WHERE owner_id = #{userId} AND is_deleted = false AND name ILIKE '%' || #{keyword} || '%'
AND is_dir = #{isDir}
ORDER BY
name size create_time
ASC DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM file_node
WHERE owner_id = #{userId}
  AND is_deleted = false
  AND name ILIKE '%' || #{keyword} || '%'

      AND is_dir = #{isDir}
